280	/// Regression test for ref.test on externalized nullable references.
281	///
282	/// The bug: runRefTestOp always created non-nullable types for externalized
283	/// references (TypeCode::Ref), discarding the original nullability info.
284	/// The fix preserves nullability by checking isNullableRefType().
285	///
286	/// This test exercises the externalized reference code path in ref.test via
287	/// the extern.convert_any + ref.test pattern, verifying correct behavior for
288	/// both nullable and non-nullable ref.test targets, as well as null and
289	/// non-null input values.
290	TEST(ExecutorRegression, RefTestNullAbility) {
291	  WasmEdge::Configure Conf;
292	  WasmEdge::VM::VM VM(Conf);
293	
294	  ASSERT_TRUE(VM.loadWasm(RefTestNullabilityWasm));
295	  ASSERT_TRUE(VM.validate());
296	  ASSERT_TRUE(VM.instantiate());
297	
298	  // --- Part 1: Non-null anyref input ---
299	  //
300	  // When a non-null anyref is externalized via extern.convert_any, the
301	  // externalized flag is set on the value. The ref.test instruction must
302	  // correctly handle this externalized type when matching against both
303	  // nullable and non-nullable extern targets.
304	  //
305	  // Note: The runtime parameter-pushing code converts non-null nullable refs
306	  // to non-nullable before execution. So the externalized type at ref.test
307	  // time will be non-nullable. Both ref.test targets should succeed.
308	  {
309	    int DummyObj = 42;
310	    RefVariant AnyRefVal(ValType(TypeCode::RefNull, TypeCode::AnyRef),
311	                         reinterpret_cast<void *>(&DummyObj));
312	
313	    std::vector<ValVariant> Params = {ValVariant(AnyRefVal)};
314	    std::vector<ValType> ParamTypes = {ValType(TypeCode::AnyRef)};
315	
316	    // Test 1: extern.convert_any + ref.test (ref null extern)
317	    // Non-null externalized ref with non-nullable type should match
318	    // nullable extern target.
319	    {
320	      auto Result = VM.execute("test_nullable", Params, ParamTypes);
321	      ASSERT_TRUE(Result);
322	      ASSERT_EQ((*Result).size(), 1U);
323	      EXPECT_EQ((*Result)[0].first.get<uint32_t>(), 1U)
324	          << "Non-null externalized anyref should match (ref null extern)";
325	    }
326	
327	    // Test 2: extern.convert_any + ref.test (ref extern)
328	    // Non-null externalized ref with non-nullable type should also match
329	    // non-nullable extern target (the externalized type is (ref extern)
330	    // because the runtime made it non-nullable before execution).
331	    {
332	      auto Result = VM.execute("test_nonnull", Params, ParamTypes);
333	      ASSERT_TRUE(Result);
334	      ASSERT_EQ((*Result).size(), 1U);
335	      EXPECT_EQ((*Result)[0].first.get<uint32_t>(), 1U)
336	          << "Non-null externalized anyref should match (ref extern)";
337	    }
338	  }
339	
340	  // --- Part 2: Null anyref input ---
341	  //
342	  // When a null anyref is externalized, extern.convert_any creates a new
343	  // RefVariant with type (ref null noextern) without setting the externalized
344	  // flag. ref.test follows the normal (non-externalized) code path.
345	  // A null value should match nullable target but not non-nullable.
346	  {
347	    RefVariant NullAnyRef(ValType(TypeCode::RefNull, TypeCode::NullRef));
348	
349	    std::vector<ValVariant> Params = {ValVariant(NullAnyRef)};
350	    std::vector<ValType> ParamTypes = {ValType(TypeCode::AnyRef)};
351	
352	    // Test 3: extern.convert_any on null + ref.test (ref null extern)
353	    // A null externalized value becomes (ref null noextern), which should
354	    // match (ref null extern) since noextern <: extern.
355	    {
356	      auto Result = VM.execute("test_nullable", Params, ParamTypes);
357	      ASSERT_TRUE(Result);
358	      ASSERT_EQ((*Result).size(), 1U);
359	      EXPECT_EQ((*Result)[0].first.get<uint32_t>(), 1U)
360	          << "Null externalized anyref should match (ref null extern)";
361	    }
362	
363	    // Test 4: extern.convert_any on null + ref.test (ref extern)
364	    // A null value should not match a non-nullable target since
365	    // (ref null noextern) is nullable.
366	    {
367	      auto Result = VM.execute("test_nonnull", Params, ParamTypes);
368	      ASSERT_TRUE(Result);
369	      ASSERT_EQ((*Result).size(), 1U);
370	      EXPECT_EQ((*Result)[0].first.get<uint32_t>(), 0U)
371	          << "Null externalized anyref should NOT match (ref extern)";
372	    }
373	  }
374	
375	  // --- Part 3: Non-null externref round-trip ---
376	  //
377	  // In this path, any.convert_extern (internalize) converts a non-null
378	  // externref to (ref any) (non-nullable), then extern.convert_any
379	  // (externalize) sets the externalized flag on this non-nullable type.
380	  // The fix correctly preserves this non-nullability. Both nullable and
381	  // non-nullable ref.test targets should match.
382	  {
383	    int DummyObj = 42;
384	    RefVariant ExternRefVal(&DummyObj);
385	
386	    std::vector<ValVariant> Params = {ValVariant(ExternRefVal)};
387	    std::vector<ValType> ParamTypes = {ValType(TypeCode::ExternRef)};
388	
389	    // Test 5: internalize + externalize + ref.test (ref null extern)
390	    // After internalize, type is (ref any) (non-nullable).
391	    // After externalize, type is (ref any) + externalized.
392	    // The fix normalizes this to (ref extern), matching (ref null extern).
393	    {
394	      auto Result = VM.execute("test_ext_nullable", Params, ParamTypes);
395	      ASSERT_TRUE(Result);
396	      ASSERT_EQ((*Result).size(), 1U);
397	      EXPECT_EQ((*Result)[0].first.get<uint32_t>(), 1U)
398	          << "Round-trip externalized externref should match (ref null extern)";
399	    }
400	
401	    // Test 6: internalize + externalize + ref.test (ref extern)
402	    // Same path, normalized to (ref extern) which matches (ref extern).
403	    {
404	      auto Result = VM.execute("test_ext_nonnull", Params, ParamTypes);
405	      ASSERT_TRUE(Result);
406	      ASSERT_EQ((*Result).size(), 1U);
407	      EXPECT_EQ((*Result)[0].first.get<uint32_t>(), 1U)
408	          << "Round-trip externalized externref should match (ref extern)";
409	    }
410	  }
411	
412	  // --- Part 4: Null externref round-trip ---
413	  //
414	  // When a null externref is internalized, it becomes (ref null none).
415	  // When externalized, a null value becomes (ref null noextern).
416	  // Neither step sets the externalized flag on the value.
417	  {
418	    RefVariant NullExternRef(
419	        ValType(TypeCode::RefNull, TypeCode::NullExternRef));
420	
421	    std::vector<ValVariant> Params = {ValVariant(NullExternRef)};
422	    std::vector<ValType> ParamTypes = {ValType(TypeCode::ExternRef)};
423	
424	    // Test 7: null externref round-trip + ref.test (ref null extern)
425	    // Should match since null noextern <: null extern.
426	    {
427	      auto Result = VM.execute("test_ext_nullable", Params, ParamTypes);
428	      ASSERT_TRUE(Result);
429	      ASSERT_EQ((*Result).size(), 1U);
430	      EXPECT_EQ((*Result)[0].first.get<uint32_t>(), 1U)
431	          << "Null round-trip externref should match (ref null extern)";
432	    }
433	
434	    // Test 8: null externref round-trip + ref.test (ref extern)
435	    // Should NOT match since null value cannot be non-nullable.
436	    {
437	      auto Result = VM.execute("test_ext_nonnull", Params, ParamTypes);
438	      ASSERT_TRUE(Result);
439	      ASSERT_EQ((*Result).size(), 1U);
440	      EXPECT_EQ((*Result)[0].first.get<uint32_t>(), 0U)
441	          << "Null round-trip externref should NOT match (ref extern)";
442	    }
443	  }
444	
445	  // --- Part 5: Direct ValType nullability preservation logic ---
446	  //
447	  // Verifies the same condition checked in runRefTestOp without going
448	  // through the full execution pipeline.
449	  {
450	    // Simulate a nullable externalized type (ref null any) + externalized flag.
451	    ValType NullableAny(TypeCode::RefNull, TypeCode::AnyRef);
452	    NullableAny.setExternalized();
453	
454	    ASSERT_TRUE(NullableAny.isExternalized());
455	    ASSERT_TRUE(NullableAny.isNullableRefType());
456	
457	    // The fix: construct the normalized type preserving nullability.
458	    ValType NormalizedNullable(
459	        NullableAny.isNullableRefType() ? TypeCode::RefNull : TypeCode::Ref,
460	        TypeCode::ExternRef);
461	    EXPECT_TRUE(NormalizedNullable.isNullableRefType())
462	        << "Normalized type should preserve nullable from source";
463	    EXPECT_FALSE(NormalizedNullable.isExternalized())
464	        << "Normalized type should not have externalize flag";
465	
466	    // Simulate a non-nullable externalized type (ref any) + externalized flag.
467	    ValType NonNullableAny(TypeCode::Ref, TypeCode::AnyRef);
468	    NonNullableAny.setExternalized();
469	
470	    ASSERT_TRUE(NonNullableAny.isExternalized());
471	    ASSERT_FALSE(NonNullableAny.isNullableRefType());
472	
473	    // The fix: non-nullable should remain non-nullable.
474	    ValType NormalizedNonNullable(
475	        NonNullableAny.isNullableRefType() ? TypeCode::RefNull : TypeCode::Ref,
476	        TypeCode::ExternRef);
477	    EXPECT_FALSE(NormalizedNonNullable.isNullableRefType())
478	        << "Normalized type should preserve non-nullable from source";
479	
480	    // Old code (the bug) would always use TypeCode::Ref:
481	    ValType OldBugResult(TypeCode::Ref, TypeCode::ExternRef);
482	    EXPECT_FALSE(OldBugResult.isNullableRefType())
483	        << "Old code always produced non-nullable";
484	
485	    // Verify the difference: for a nullable input, old and new code differ.
486	    EXPECT_NE(NormalizedNullable.isNullableRefType(),
487	              OldBugResult.isNullableRefType())
